using MeAjudaAi.Shared.Database;
using MeAjudaAi.Modules.ServiceCatalogs.Application.Commands.Service;  using MeAjudaAi.Modules.ServiceCatalogs.Domain.ValueObjects; using MeAjudaAi.Shared.Commands; using MeAjudaAi.Contracts.Functional; using MeAjudaAi.Contracts.Modules.Providers; using MeAjudaAi.Contracts.Utilities.Constants; using ServiceEntity = MeAjudaAi.Modules.ServiceCatalogs.Domain.Entities.Service;  namespace MeAjudaAi.Modules.ServiceCatalogs.Application.Handlers.Commands.Service;  public sealed class DeleteServiceCommandHandler(     IUnitOfWork uow,     IProvidersModuleApi providersModuleApi)     : ICommandHandler<DeleteServiceCommand, Result> {     public async Task<Result> HandleAsync(DeleteServiceCommand request, CancellationToken cancellationToken = default)     {         if (request.Id == Guid.Empty)             return Result.Failure(ValidationMessages.Required.Id);          var serviceRepository = uow.GetRepository<ServiceEntity, ServiceId>();         var service = await serviceRepository.TryFindAsync(ServiceId.From(request.Id), cancellationToken);          if (service is null)             return Result.Failure(Error.NotFound(ValidationMessages.NotFound.Service));          var hasProvidersResult = await providersModuleApi.HasProvidersOfferingServiceAsync(request.Id, cancellationToken);          if (hasProvidersResult.IsFailure)             return Result.Failure(hasProvidersResult.Error);          if (hasProvidersResult.Value)             return Result.Failure(string.Format(ValidationMessages.Catalogs.CannotDeleteServiceOffered, service.Name));          serviceRepository.Delete(service);         await uow.SaveChangesAsync(cancellationToken);          return Result.Success();     } }
